const input = $input.first().json;
const { token, job_id } = input.body || input;

// Validate required fields
if (!token) {
  return [{ json: { error: true, code: 'MISSING_TOKEN', message: 'Token is required' } }];
}
if (!job_id) {
  return [{ json: { error: true, code: 'MISSING_JOB_ID', message: 'job_id is required' } }];
}

// Validate job_id format (UUID or numeric)
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const numericRegex = /^\d+$/;
if (!uuidRegex.test(job_id) && !numericRegex.test(job_id)) {
  return [{ json: { error: true, code: 'INVALID_JOB_ID', message: 'job_id must be a valid UUID or numeric ID' } }];
}

// Decode JWT
try {
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Invalid token format');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());

  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: true, code: 'TOKEN_EXPIRED', message: 'Token has expired' } }];
  }

  const vendor_id = payload.sub || payload.vendor_id || payload.user_id;
  if (!vendor_id) {
    return [{ json: { error: true, code: 'INVALID_TOKEN', message: 'Token missing subject' } }];
  }

  return [{ json: {
    error: false,
    vendor_id,
    job_id
  } }];
} catch (e) {
  return [{ json: { error: true, code: 'AUTH_FAILED', message: 'Token verification failed: ' + e.message } }];
}

const response = $input.first().json;
const authData = $('Verify Token').first().json;

// Supabase returns an array
const jobs = Array.isArray(response) ? response : [response];

if (!jobs || jobs.length === 0 || !jobs[0]?.id) {
  return [{ json: {
    success: false,
    error: 'job_not_found',
    message: `Job ${authData.job_id} not found or access denied`
  } }];
}

const job = jobs[0];

// Parse result_data if it's a string
let result_data = job.result_data;
if (typeof result_data === 'string') {
  try {
    result_data = JSON.parse(result_data);
  } catch (e) {
    result_data = null;
  }
}

// Calculate progress percentage
const progress = job.total_products > 0 
  ? Math.round((job.processed_products / job.total_products) * 100) 
  : 0;

// Calculate elapsed time
let elapsed_seconds = null;
if (job.started_at) {
  const start = new Date(job.started_at).getTime();
  const end = job.completed_at ? new Date(job.completed_at).getTime() : Date.now();
  elapsed_seconds = Math.round((end - start) / 1000);
}

return [{ json: {
  success: true,
  job_id: job.id,
  status: job.status,
  tool: job.tool,
  marketplace: job.marketplace,
  total_products: job.total_products,
  processed_products: job.processed_products,
  error_count: job.error_count,
  progress,
  result_data,
  created_at: job.created_at,
  started_at: job.started_at,
  completed_at: job.completed_at,
  elapsed_seconds,
  is_complete: ['completed', 'failed', 'cancelled'].includes(job.status)
} }];
